public ResultSet Query(int id){
    ResultSet rs=null;
    try{
        Statement st=getConn().createStatement();
        if(id==0)
            rs=st.executeQuery("select*from session");
        else
            rs=st.executeQuery("select*from session where sessionid="+id);
    }catch(Exception e){
        e.printStackTrace();
    }
    return rs;
 }
```

