            }
        }
    </style>
</head>
<body>
    <div class="container">
        <header>
            <h1>AJAX 实时天气应用</h1>
            <p class="subtitle">使用 AJAX 技术获取实时天气数据</p>
        </header>

        <div class="search-container">
            <div class="search-box">
                <input type="text" class="search-input" placeholder="输入城市名称，如：北京、上海、纽约..." id="city-input">
