    </div>

    <script>
        // 模拟天气API响应数据
        const mockWeatherData = {
            '北京': {
                current: {
                    temp: 25,
                    feels_like: 26,
                    humidity: 65,
                    wind_speed: 3.6,
                    pressure: 1015,
