    <script>
        // 模拟服务器端的Session存储
        let sessionStorage = {};
        let currentSessionId = null;

        // 生成随机ID函数
        function generateId() {
            return 'session_' + Math.random().toString(36).substr(2, 9);
        }

        // 显示状态消息
        function showMessage(message, type) {
            const messageEl = document.getElementById('status-message');
            messageEl.textContent = message;
            messageEl.className = `status-message status-${type}`;
            messageEl.style.display = 'block';

            setTimeout(() => {
                messageEl.style.display = 'none';
            }, 3000);
        }

        // 设置Cookie
        function setCookie(name, value, days) {
            let expires = "";
            if (days) {
                const date = new Date();
                date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
                expires = "; expires=" + date.toUTCString();
            }
            document.cookie = name + "=" + (value || "") + expires + "; path=/";
            updateDisplay();
        }

        // 获取Cookie
        function getCookie(name) {
            const nameEQ = name + "=";
            const ca = document.cookie.split(';');
            for(let i = 0; i < ca.length; i++) {
                let c = ca[i];
                while (c.charAt(0) === ' ') c = c.substring(1, c.length);
                if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
            }
            return null;
        }

        // 删除Cookie
        function deleteCookie(name) {
            document.cookie = name + '=; expires=Thu, 01 Jan 1970 00:00:01 GMT; path=/';
            updateDisplay();
        }

        // 创建Session
        function createSession(userData) {
            const sessionId = generateId();
            sessionStorage[sessionId] = {
                user: userData,
                createdAt: new Date().toISOString(),
                lastActivity: new Date().toISOString()
            };
            currentSessionId = sessionId;

            // 设置Session Cookie（浏览器关闭时过期）
            setCookie('session_id', sessionId, 0);

            return sessionId;
        }

        // 获取Session数据
        function getSession() {
            const sessionId = getCookie('session_id');
            if (sessionId && sessionStorage[sessionId]) {
                // 更新最后活动时间
                sessionStorage[sessionId].lastActivity = new Date().toISOString();
                currentSessionId = sessionId;
                return sessionStorage[sessionId];
            }
            return null;
        }

        // 销毁Session
        function destroySession() {
            const sessionId = getCookie('session_id');
            if (sessionId) {
                delete sessionStorage[sessionId];
                deleteCookie('session_id');
                currentSessionId = null;
            }
        }

        // 更新显示
        function updateDisplay() {
            // 显示Cookie数据
            const rememberMe = getCookie('remember_me');
            document.getElementById('cookie-data').textContent = 
                rememberMe ? `用户名: ${rememberMe}` : '无';

            // 显示Session数据
            const session = getSession();
            if (session) {
                document.getElementById('session-data').textContent = 
                    `用户: ${session.user.username}, 登录时间: ${new Date(session.createdAt).toLocaleTimeString()}`;
                document.getElementById('session-id').textContent = currentSessionId;
            } else {
                document.getElementById('session-data').textContent = '无';
                document.getElementById('session-id').textContent = '未生成';
            }
        }

        // 登录功能
        document.getElementById('login-btn').addEventListener('click', function() {
            const username = document.getElementById('username').value;
            const password = document.getElementById('password').value;
            const rememberMe = document.getElementById('remember-me').checked;

            if (!username || !password) {
                showMessage('请输入用户名和密码', 'error');
                return;
            }

            // 模拟登录验证
            if (username === 'admin' && password === '123456') {
                // 创建Session（总是创建）
                createSession({ username, loginTime: new Date().toISOString() });

                // 如果选择"记住我"，设置长期Cookie
                if (rememberMe) {
                    setCookie('remember_me', username, 30); // 30天有效期
                } else {
                    deleteCookie('remember_me');
                }

                // 更新界面
                document.getElementById('login-form').style.display = 'none';
                document.getElementById('user-panel').style.display = 'block';
                document.getElementById('welcome-user').textContent = username;

                showMessage('登录成功！', 'success');
                updateDisplay();
            } else {
                showMessage('用户名或密码错误', 'error');
            }
        });

        // 退出登录
        document.getElementById('logout-btn').addEventListener('click', function() {
            destroySession();
            deleteCookie('remember_me');

            document.getElementById('login-form').style.display = 'block';
            document.getElementById('user-panel').style.display = 'none';
            document.getElementById('username').value = '';
            document.getElementById('password').value = '';

            showMessage('已退出登录', 'success');
            updateDisplay();
        });

        // 页面加载时检查记住我状态
        window.addEventListener('load', function() {
            const rememberedUser = getCookie('remember_me');
            if (rememberedUser) {
                document.getElementById('username').value = rememberedUser;
                document.getElementById('remember-me').checked = true;
            }

            // 检查是否有活跃Session
            const session = getSession();
            if (session) {
                document.getElementById('login-form').style.display = 'none';
                document.getElementById('user-panel').style.display = 'block';
                document.getElementById('welcome-user').textContent = session.user.username;
            }

            updateDisplay();
        });

        // 模拟自动Session过期（15秒后）
        setInterval(() => {
            const session = getSession();
            if (session) {
                const lastActivity = new Date(session.lastActivity);
                const now = new Date();
                const diff = (now - lastActivity) / 1000; // 秒

                if (diff > 15) { // 15秒后过期
                    destroySession();
                    document.getElementById('login-form').style.display = 'block';
                    document.getElementById('user-panel').style.display = 'none';
                    showMessage('会话已过期，请重新登录', 'error');
                    updateDisplay();
                }
            }
        }, 5000);
    </script>
</body>
</html>
```

## 三、核心区别总结

| 特性         | Cookie                   | Session                      |
| ------------ | ------------------------ | ---------------------------- |
| **存储位置** | 客户端浏览器             | 服务器端                     |
| **安全性**   | 较低（用户可见可修改）   | 较高（服务器控制）           |
| **存储容量** | 约4KB                    | 较大（依赖服务器配置）       |
| **生命周期** | 可设置长期有效           | 浏览器关闭或超时失效         |
| **性能影响** | 每次请求自动携带         | 服务器资源占用               |
| **适用场景** | 用户偏好、追踪、临时数据 | 登录状态、敏感信息、交易数据 |

## 四、最佳实践建议

1. **混合使用**：结合两者优势，用Session存储敏感信息，用Cookie存储非敏感偏好设置

2. **安全措施**：
   - 对敏感Cookie设置HttpOnly和Secure标志
   - 使用HTTPS传输
   - 定期更换Session ID

3. **性能优化**：
   - 避免在Cookie中存储大量数据
   - 合理设置Session超时时间
   - 对大型应用考虑分布式Session存储

这个示例完整展示了Cookie和Session的概念、区别以及在实际应用中的不同使用场景！

我们来系统地复习一下 Java Stream 流。这是一种在 Java 8 中引入的 API，用于以声明式方式处理数据集合（如 List、Set、Map 等）。它可以让你写出更简洁、更易读、更高效的代码。

---

### 第一部分：核心概念

**1. 什么是 Stream？**
Stream（流）是一个来自数据源（如集合、数组）的元素队列，并支持聚合操作。它自己**不存储数据**，而是通过一个计算管道来处理数据。

**2. 流的特点**
*   **不是数据结构**：它本身不存储任何数据，数据来自其源（如集合）。
*   **函数式风格**：对流的操作会产生一个结果，但不会修改其源。例如，对一个集合进行过滤，会生成一个新的流，而不是删除集合中的元素。
*   **惰性执行**：许多流操作（如过滤、映射）可以是“惰性的”，这意味着它们只有在需要结果时才会执行。
*   **只能遍历一次**：像迭代器一样，流在生命周期内只能被消费一次。一旦遍历结束，流就关闭了。如果你想再次操作，必须重新创建流。
*   **可并行化**：流操作可以透明地利用多核架构，你只需要将 `stream()` 改为 `parallelStream()`，而逻辑代码无需改变。


**3. 流的操作流程**
流的操作分为两个阶段，连接起来形成一个“流管道”。
1.  **中间操作**：返回一个新的流，可以连续多个。它们是惰性的，不立即执行。
    *   例如：`filter()`, `map()`, `sorted()`, `distinct()`, `limit()`
2.  **终端操作**：返回一个非流的结果（如 `void`、`List`、`Optional`、`Integer` 等）。它会触发整个流水线的实际执行。
    *   例如：`forEach()`, `collect()`, `count()`, `reduce()`, `findFirst()`

**流程示意图：**
`数据源 -> (中间操作1 -> 中间操作2 -> ...) -> 终端操作 -> 结果`

---

### 第二部分：实际应用问题

让我们通过一个具体的例子来应用这些概念。

**问题场景：**
我们有一个 `Employee`（员工）类，包含以下属性：`id`（编号）、`name`（姓名）、`age`（年龄）、`salary`（薪资）、`department`（部门）。
我们有一个包含多个员工的 List。

**目标：**
1.  找出所有在“技术部”且年龄大于 25 岁的员工。
2.  提取出这些员工的姓名。
3.  将这些姓名按字母顺序排序。
4.  将最终结果收集到一个新的 List 中。

**传统方式（循环和条件判断）：**
```java
List<Employee> filteredList = new ArrayList<>();
for (Employee emp : employeeList) {
    if ("技术部".equals(emp.getDepartment()) && emp.getAge() > 25) {
        filteredList.add(emp);
    }
}

List<String> nameList = new ArrayList<>();
for (Employee emp : filteredList) {
    nameList.add(emp.getName());
}

Collections.sort(nameList);
```

**Stream 方式：**
```java
List<String> result = employeeList.stream() // 1. 创建流
        .filter(emp -> "技术部".equals(emp.getDepartment())) // 2. 中间操作：过滤部门
        .filter(emp -> emp.getAge() > 25) // 3. 中间操作：过滤年龄
        .map(Employee::getName) // 4. 中间操作：将Employee对象映射为其姓名（String）
        .sorted() // 5. 中间操作：对姓名进行自然排序
        .collect(Collectors.toList()); // 6. 终端操作：将结果收集到List中
```
**stream流的流程图**

```mermaid
graph TD;
    A[Start] --> B[Create Stream from employeeList];
    B --> C[Filter by Department: 技术部];
    C --> D[Filter by Age > 25];
    D --> E[Map to Names];
    E --> F[Sort Names];
    F --> G[Collect to nameList];
    G --> H[End];
```

**代码分析：**
*   `stream()`：从 `employeeList` 创建流。
*   `filter(...)`：两个连续的过滤操作，是中间操作。它们会等待终端操作的触发。
*   `map(Employee::getName)`：这是一个关键的中间操作。它将流中的 `Employee` 元素转换为 `String`（员工姓名）元素。现在流的类型从 `Stream<Employee>` 变成了 `Stream<String>`。
*   `sorted()`：对 `Stream<String>` 中的字符串进行排序。
*   `collect(Collectors.toList())`：这是终端操作。它触发了前面所有中间操作的执行，并将最终的 `Stream<String>` 收集到一个 `List<String>` 中。

可以看到，Stream 代码更加**声明式**（“做什么”而不是“怎么做”），逻辑清晰，一气呵成，并且没有改变原始的 `employeeList`。

---

### 第三部分：常用的流使用方式

这里列出一些最常用和强大的流操作组合。

**1. 过滤与收集**
```java
// 找出所有薪资超过 10000 的员工
List<Employee> wellPaid = employeeList.stream()
        .filter(emp -> emp.getSalary() > 10000)
        .collect(Collectors.toList());

// 获取所有不同的部门
Set<String> departments = employeeList.stream()
        .map(Employee::getDepartment)
        .collect(Collectors.toSet()); // 用Set自动去重
```

**2. 映射（提取信息或转换）**
```java
// 获取所有员工的姓名列表
List<String> names = employeeList.stream()
        .map(Employee::getName) // 方法引用，等价于 .map(emp -> emp.getName())
        .collect(Collectors.toList());

// 将每个员工的姓名转换为大写
List<String> upperCaseNames = employeeList.stream()
        .map(Employee::getName)
        .map(String::toUpperCase)
        .collect(Collectors.toList());
```

**3. 查找与匹配**
```java
// 检查是否有员工在“财务部”
boolean hasFinance = employeeList.stream()
        .anyMatch(emp -> "财务部".equals(emp.getDepartment()));

// 检查是否所有员工都大于18岁
boolean allAdult = employeeList.stream()
        .allMatch(emp -> emp.getAge() >= 18);

// 查找第一个在“人事部”的员工
Optional<Employee> firstHr = employeeList.stream()
        .filter(emp -> "人事部".equals(emp.getDepartment()))
        .findFirst();
// 使用Optional安全地处理结果
firstHr.ifPresent(emp -> System.out.println(emp.getName()));
```

**4. 归约与聚合**
```java
// 计算技术部员工的平均薪资
OptionalDouble avgSalary = employeeList.stream()
        .filter(emp -> "技术部".equals(emp.getDepartment()))
        .mapToDouble(Employee::getSalary) // 转换为DoubleStream，有专门的统计方法
        .average();

// 计算公司总薪资支出
double totalSalary = employeeList.stream()
        .mapToDouble(Employee::getSalary)
        .sum();

// 找出薪资最高的员工
Optional<Employee> topEarner = employeeList.stream()
        .max(Comparator.comparingDouble(Employee::getSalary));
```

**5. 分组**
```java
// 按部门对员工进行分组
Map<String, List<Employee>> byDept = employeeList.stream()
        .collect(Collectors.groupingBy(Employee::getDepartment));

// 按薪资范围分组（例如：<5000, 5000-10000, >10000）
Map<String, List<Employee>> bySalaryRange = employeeList.stream()
        .collect(Collectors.groupingBy(emp -> {
            if (emp.getSalary() < 5000) return "低";
            else if (emp.getSalary() <= 10000) return "中";
            else return "高";
        }));
```

**6. 链式操作的综合示例**
```java
// 统计技术部员工的数量
long count = employeeList.stream()
        .filter(emp -> "技术部".equals(emp.getDepartment()))
        .count();

// 获取技术部员工姓名，按薪资降序排列的前3名
List<String> topTechNames = employeeList.stream()
        .filter(emp -> "技术部".equals(emp.getDepartment()))
        .sorted(Comparator.comparingDouble(Employee::getSalary).reversed())
        .limit(3)
        .map(Employee::getName)
        .collect(Collectors.toList());
```

### 总结

Java Stream API 的核心在于 **声明式编程** 和 **函数式组合**。通过将多个简单的中间操作（`filter`, `map`, `sorted`）连接起来，最后以一个终端操作（`collect`, `forEach`, `count`）收尾，你可以构建出非常强大且易读的数据处理管道。

多加练习，你会发现自己处理集合数据的代码会变得异常简洁和优雅。

好的，我们来系统地复习 Java 线程相关的知识。线程是 Java 并发编程的核心，理解它对于编写高性能、响应式的应用程序至关重要。

---

### 第一部分：核心概念

#### 1. 进程 vs 线程

**进程**：
- 操作系统资源分配的基本单位
- 每个进程有独立的内存空间（堆、栈、代码区）
- 进程间通信（IPC）比较复杂（如管道、信号、共享内存等）
- 创建和销毁开销较大

**线程**：
- CPU 调度的基本单位，是进程内的执行单元
- 同一进程的线程共享堆和方法区，但有独立的程序计数器和栈
- 线程间通信相对简单（共享内存）
- 创建和销毁开销较小

#### 2. 线程的生命周期（状态）

Java 线程有 6 种状态：
1. **NEW**（新建）：线程被创建但尚未启动
2. **RUNNABLE**（可运行）：正在运行或准备运行
3. **BLOCKED**（阻塞）：等待监视器锁（synchronized）
4. **WAITING**（等待）：无限期等待其他线程的特定动作
5. **TIMED_WAITING**（超时等待）：有限时间等待
6. **TERMINATED**（终止）：线程执行完毕

#### 3. 创建线程的三种方式

**1. 继承 Thread 类**
```java
class MyThread extends Thread {
    @Override
    public void run() {
        System.out.println("线程执行: " + Thread.currentThread().getName());
    }
}

// 使用
MyThread thread = new MyThread();
thread.start();
```

**2. 实现 Runnable 接口**（推荐）
```java
class MyRunnable implements Runnable {
    @Override
    public void run() {
        System.out.println("线程执行: " + Thread.currentThread().getName());
    }
}

// 使用
Thread thread = new Thread(new MyRunnable());
thread.start();
```

**3. 实现 Callable 接口**（可返回结果）
```java
class MyCallable implements Callable<String> {
    @Override
    public String call() throws Exception {
        Thread.sleep(1000);
        return "任务完成: " + Thread.currentThread().getName();
    }
}
```

#### 4. 线程同步与锁

**关键问题**：多个线程访问共享资源时可能出现**竞态条件**。

**解决方案**：
1. **synchronized 关键字**
   - 同步方法
   - 同步代码块

2. **Lock 接口**（更灵活）
   - `ReentrantLock`：可重入锁
   - `ReadWriteLock`：读写锁

#### 5. 线程通信

- `wait()`：让当前线程等待
- `notify()`：唤醒一个等待的线程
- `notifyAll()`：唤醒所有等待的线程

#### 6. volatile 关键字

保证变量的可见性，但不保证原子性。

