        }

        .product-price {
            font-size: 1.5rem;
            color: #e74c3c;
            margin-bottom: 15px;
            font-weight: bold;
        }

        .add-to-cart {
            width: 100%;
            padding: 10px;
            background: #3498db;
            color: white;
            border: none;
            border-radius: 5px;
            cursor: pointer;
            font-size: 1rem;
            transition: background 0.3s;
        }

        .add-to-cart:hover {
            background: #2980b9;
        }

        .cart-title {
            font-size: 1.5rem;
            margin-bottom: 20px;
            color: #2c3e50;
            border-bottom: 2px solid #eee;
            padding-bottom: 10px;
        }

        .cart-items {
            margin-bottom: 20px;
            max-height: 400px;
            overflow-y: auto;
