<body>
    <div class="container">
        <h1>jQuery 购物车示例</h1>

        <div class="content">
            <div class="products">
                <!-- 产品将通过jQuery动态添加 -->
            </div>

            <div class="cart-container">
                <h2 class="cart-title">购物车</h2>
                <div class="cart-items">
                    <div class="empty-cart">购物车为空</div>
                </div>
                <div class="cart-total">总计: ¥0.00</div>
                <button class="checkout-btn" disabled>结算</button>
            </div>
        </div>
    </div>

    <div class="notification">商品已添加到购物车！</div>

    <script>
        // 产品数据
        const products = [
            { id: 1, name: "无线耳机", price: 299, icon: "🎧" },
            { id: 2, name: "智能手机", price: 3999, icon: "📱" },
            { id: 3, name: "平板电脑", price: 2599, icon: "📟" },
            { id: 4, name: "智能手表", price: 1299, icon: "⌚" },
            { id: 5, name: "蓝牙音箱", price: 399, icon: "🔊" },
            { id: 6, name: "笔记本电脑", price: 5999, icon: "💻" }
        ];

        // 购物车数据
        let cart = [];

        // 文档就绪后执行 - jQuery核心特性
        $(document).ready(function() {
            // 渲染产品列表
            renderProducts();

            // 更新购物车显示
            updateCartDisplay();

            // 绑定结算按钮事件
            $('.checkout-btn').on('click', function() {
                if (cart.length > 0) {
                    alert('感谢您的购买！总金额：¥' + calculateTotal().toFixed(2));
                    // 清空购物车
                    cart = [];
                    updateCartDisplay();
                }
            });
        });

        // 渲染产品列表
        function renderProducts() {
            const $productsContainer = $('.products');

            // 使用jQuery遍历产品数据并创建产品卡片
            $.each(products, function(index, product) {
                const $productCard = $('<div>').addClass('product-card');

                $productCard.html(`
                    <div class="product-image">${product.icon}</div>
                    <div class="product-info">
                        <h3 class="product-title">${product.name}</h3>
                        <div class="product-price">¥${product.price.toFixed(2)}</div>
                        <button class="add-to-cart" data-id="${product.id}">加入购物车</button>
                    </div>
                `);

                // 添加到产品容器
                $productsContainer.append($productCard);
            });

            // 使用事件委托绑定添加购物车事件
            $('.products').on('click', '.add-to-cart', function() {
                const productId = parseInt($(this).data('id'));
                addToCart(productId);
                showNotification();
            });
        }

        // 添加商品到购物车
        function addToCart(productId) {
            const product = products.find(p => p.id === productId);

            if (product) {
                // 检查商品是否已在购物车中
                const existingItem = cart.find(item => item.id === productId);

                if (existingItem) {
                    existingItem.quantity++;
                } else {
                    cart.push({
                        id: product.id,
                        name: product.name,
                        price: product.price,
                        quantity: 1,
                        icon: product.icon
                    });
                }

                // 更新购物车显示
                updateCartDisplay();
            }
        }

        // 更新购物车显示
        function updateCartDisplay() {
            const $cartItems = $('.cart-items');
            const $cartTotal = $('.cart-total');
            const $checkoutBtn = $('.checkout-btn');
            const $emptyCart = $cartItems.find('.empty-cart');

            // 清空购物车显示
            $cartItems.find('.cart-item').remove();

            if (cart.length === 0) {
                // 显示购物车为空消息
                if ($emptyCart.length === 0) {
                    $cartItems.append('<div class="empty-cart">购物车为空</div>');
                } else {
                    $emptyCart.show();
                }
                $checkoutBtn.prop('disabled', true);
            } else {
                // 隐藏购物车为空消息
                $emptyCart.hide();

                // 添加购物车商品
                $.each(cart, function(index, item) {
                    const $cartItem = $('<div>').addClass('cart-item');

                    $cartItem.html(`
                        <div class="item-name">
                            <span>${item.icon}</span> ${item.name}
                        </div>
                        <div class="item-quantity">
                            <button class="quantity-btn minus" data-id="${item.id}">-</button>
                            <span>${item.quantity}</span>
                            <button class="quantity-btn plus" data-id="${item.id}">+</button>
                        </div>
                        <div class="item-price">¥${(item.price * item.quantity).toFixed(2)}</div>
                        <button class="remove-btn" data-id="${item.id}">删除</button>
                    `);

                    $cartItems.append($cartItem);
                });

                $checkoutBtn.prop('disabled', false);
            }

            // 更新总计
            const total = calculateTotal();
            $cartTotal.text(`总计: ¥${total.toFixed(2)}`);

            // 绑定购物车项目事件
            bindCartItemEvents();
        }

        // 绑定购物车项目事件
        function bindCartItemEvents() {
            // 减少数量
            $('.minus').on('click', function() {
                const productId = parseInt($(this).data('id'));
                const item = cart.find(item => item.id === productId);

                if (item && item.quantity > 1) {
                    item.quantity--;
                    updateCartDisplay();
                }
            });

            // 增加数量
            $('.plus').on('click', function() {
                const productId = parseInt($(this).data('id'));
                const item = cart.find(item => item.id === productId);

                if (item) {
                    item.quantity++;
                    updateCartDisplay();
                }
            });

            // 删除商品
            $('.remove-btn').on('click', function() {
                const productId = parseInt($(this).data('id'));
                cart = cart.filter(item => item.id !== productId);
                updateCartDisplay();
            });
        }

        // 计算购物车总价
        function calculateTotal() {
            let total = 0;
            $.each(cart, function(index, item) {
                total += item.price * item.quantity;
            });
            return total;
        }

        // 显示通知
        function showNotification() {
            const $notification = $('.notification');

            // 使用jQuery动画显示通知
            $notification.fadeIn(300);

            // 3秒后自动隐藏
            setTimeout(function() {
                $notification.fadeOut(300);
            }, 3000);
        }
    </script>
</body>
</html>
```

## 四、jQuery 核心优势总结

通过上面的购物车示例，我们可以看到 jQuery 的以下优势：

1. **简洁的DOM操作** - 使用 `$()` 选择器快速获取元素
2. **链式调用** - 方法可以连续调用，代码更简洁
3. **事件处理** - 统一的事件绑定方法，兼容不同浏览器
4. **动画效果** - 内置的动画方法如 `fadeIn()`, `fadeOut()`
5. **Ajax支持** - 简化异步请求处理
6. **跨浏览器兼容** - 自动处理浏览器差异

## 五、jQuery 在现代开发中的定位

虽然现代前端开发中，React、Vue 等框架更为流行，但 jQuery 仍然在以下场景中有其价值：

- 传统项目的维护和升级
- 简单的交互需求，不需要复杂状态管理
- 与其他库或框架的集成
- 快速原型开发

